#!/usr/bin/env node
import { existsSync, readdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';

const repoRoot = process.cwd();
const ledgerPath = path.join(repoRoot, 'open-source/gnosis/THEOREM_LEDGER.md');
const auditPath = path.join(
  repoRoot,
  'apps/mcp-superserver/src/ledger-tool-audit.generated.json'
);
const reportPath = path.join(repoRoot, 'open-source/gnosis/FALLBACK_PROOF_ARTIFACTS.md');

function splitMarkdownRow(line) {
  const cells = [];
  let current = '';
  let inBackticks = false;

  for (const char of line) {
    if (char === '`') {
      inBackticks = !inBackticks;
      current += char;
      continue;
    }
    if (char === '|' && !inBackticks) {
      cells.push(current.trim());
      current = '';
      continue;
    }
    current += char;
  }

  cells.push(current.trim());
  if (cells[0] === '') cells.shift();
  if (cells[cells.length - 1] === '') cells.pop();
  return cells;
}

function cleanCell(cell) {
  return cell.replace(/^`/u, '').replace(/`$/u, '').replace(/\s+/gu, ' ').trim();
}

function candidateArtifactPaths(reference) {
  const candidates = [];
  if (reference.startsWith('open-source/')) candidates.push(reference);
  if (reference.startsWith('Gnosis/')) {
    candidates.push(`open-source/gnosis-math/${reference}`);
  }
  if (
    reference.startsWith('lean/') ||
    reference.startsWith('src/') ||
    reference.startsWith('topologies/') ||
    reference.startsWith('examples/')
  ) {
    candidates.push(`open-source/gnosis/${reference}`);
  }
  if (reference.endsWith('.lean') && !reference.includes('/')) {
    candidates.push(`open-source/gnosis-math/Gnosis/${reference}`);
    candidates.push(`open-source/gnosis/lean/Lean/ForkRaceFoldTheorems/${reference}`);
    const nestedGnosisMathCandidate = findFirstFileByBasename(
      'open-source/gnosis-math/Gnosis',
      reference
    );
    if (nestedGnosisMathCandidate) candidates.push(nestedGnosisMathCandidate);
  }
  if (reference.endsWith('.tla') && !reference.includes('/')) {
    candidates.push(`open-source/gnosis/tla/${reference}`);
  }
  if (reference.endsWith('.cfg') && !reference.includes('/')) {
    candidates.push(`open-source/gnosis/tla/${reference}`);
  }
  return [...new Set(candidates)];
}

function findFirstFileByBasename(directoryRelativePath, basename) {
  const directoryPath = path.join(repoRoot, directoryRelativePath);
  if (!existsSync(directoryPath)) return null;

  const stack = [directoryPath];
  while (stack.length > 0) {
    const currentPath = stack.pop();
    if (!currentPath) continue;
    const entries = readdirSync(currentPath, { withFileTypes: true }).sort((left, right) =>
      left.name.localeCompare(right.name)
    );
    for (const entry of entries) {
      const entryPath = path.join(currentPath, entry.name);
      if (entry.isDirectory()) {
        stack.push(entryPath);
      } else if (entry.name === basename) {
        return path.relative(repoRoot, entryPath);
      }
    }
  }

  return null;
}

function artifactReferences(mechanization) {
  return [...mechanization.matchAll(/`([^`]+\.(?:lean|tla|cfg|gg|ts|tsx|rs|json|md))`/gu)]
    .map((match) => match[1])
    .filter(Boolean);
}

function normalizeStem(value) {
  return path
    .basename(value)
    .replace(/\.[^.]+$/u, '')
    .toLowerCase()
    .replace(/[^a-z0-9]/gu, '');
}

function collectFiles(directoryRelativePath, extensions) {
  const directoryPath = path.join(repoRoot, directoryRelativePath);
  if (!existsSync(directoryPath)) return [];

  const files = [];
  const stack = [directoryPath];
  while (stack.length > 0) {
    const currentPath = stack.pop();
    if (!currentPath) continue;
    const entries = readdirSync(currentPath, { withFileTypes: true }).sort((left, right) =>
      left.name.localeCompare(right.name)
    );
    for (const entry of entries) {
      const entryPath = path.join(currentPath, entry.name);
      if (entry.isDirectory()) {
        stack.push(entryPath);
      } else if (extensions.some((extension) => entry.name.endsWith(extension))) {
        files.push(path.relative(repoRoot, entryPath));
      }
    }
  }

  return files;
}

const sourceCounterpartByStem = new Map();
for (const file of [
  ...collectFiles('open-source/gnosis/src', ['.ts', '.tsx']),
  ...collectFiles('open-source/gnosis/topologies', ['.gg']),
]) {
  const stem = normalizeStem(file);
  const files = sourceCounterpartByStem.get(stem) ?? [];
  files.push(file);
  sourceCounterpartByStem.set(stem, files);
}

const audit = JSON.parse(readFileSync(auditPath, 'utf8'));
const fallbackIds = new Set(
  audit.entries
    .filter((entry) => entry.proofArtifactPath === 'open-source/gnosis/THEOREM_LEDGER.md')
    .map((entry) => entry.theoremId)
);

const rowsById = new Map();
let rowNumber = 0;
for (const line of readFileSync(ledgerPath, 'utf8').split(/\r?\n/gu)) {
  if (!line.startsWith('|') || line.includes('---')) continue;
  const cells = splitMarkdownRow(line);
  if (cells.length < 3) continue;
  const theoremId = cleanCell(cells[0] ?? '');
  if (!fallbackIds.has(theoremId)) continue;

  rowNumber += 1;
  const mechanization =
    cells.length >= 4 ? cleanCell(cells[cells.length - 2] ?? '') : cleanCell(cells[2] ?? '');
  rowsById.set(theoremId, {
    theoremId,
    claim: cleanCell(cells[1] ?? ''),
    mechanization,
    rowNumber,
  });
}

const resolvable = [];
const staleReferences = [];
const ledgerOnly = [];
const sourceCounterparts = [];

for (const theoremId of fallbackIds) {
  const row = rowsById.get(theoremId);
  if (!row) continue;
  const references = artifactReferences(row.mechanization);
  const resolved = references
    .flatMap((reference) =>
      candidateArtifactPaths(reference)
        .filter((candidate) => existsSync(path.join(repoRoot, candidate)))
        .map((candidate) => ({ reference, candidate }))
    );

  if (resolved.length > 0) {
    resolvable.push({ ...row, resolved });
  } else if (references.length > 0) {
    const counterparts = references.flatMap((reference) =>
      sourceCounterpartByStem.get(normalizeStem(reference)) ?? []
    );
    const uniqueCounterparts = [...new Set(counterparts)];
    if (uniqueCounterparts.length > 0) {
      sourceCounterparts.push({ ...row, references, counterparts: uniqueCounterparts });
    }
    staleReferences.push({ ...row, references, counterparts: uniqueCounterparts });
  } else {
    ledgerOnly.push(row);
  }
}

function tableCell(value) {
  return String(value).replaceAll('|', '\\|');
}

const lines = [
  '# Fallback Proof Artifacts',
  '',
  'Parent: [Gnosis](./README.md)',
  '',
  'Generated by `node open-source/gnosis/scripts/audit-ledger-fallback-artifacts.mjs`.',
  '',
  'This report classifies MCP ledger rows whose generated `proofArtifactPath` still falls back to `open-source/gnosis/THEOREM_LEDGER.md`.',
  '',
  '## Summary',
  '',
  `- Ledger fallback rows: ${fallbackIds.size}`,
  `- Rows with currently resolvable artifact references: ${resolvable.length}`,
  `- Rows with stale file-looking references: ${staleReferences.length}`,
  `- Stale rows with matching source/topology counterparts: ${sourceCounterparts.length}`,
  `- Rows with ledger-only mechanization text: ${ledgerOnly.length}`,
  '',
  '## Resolvable References',
  '',
  '| Theorem ID | Resolved artifact candidates |',
  '|---|---|',
];

for (const row of resolvable) {
  const candidates = row.resolved
    .map((entry) => `\`${entry.reference}\` -> \`${entry.candidate}\``)
    .join('<br>');
  lines.push(`| \`${row.theoremId}\` | ${candidates} |`);
}

lines.push(
  '',
  '## Stale File-Looking References',
  '',
  '| Theorem ID | References |',
  '|---|---|'
);
for (const row of staleReferences.slice(0, 200)) {
  const references = row.references.map((reference) => `\`${reference}\``).join('<br>');
  lines.push(`| \`${row.theoremId}\` | ${references} |`);
}
if (staleReferences.length > 200) {
  lines.push(`| ... | ${staleReferences.length - 200} more rows omitted from this preview |`);
}

lines.push(
  '',
  '## Source Counterparts For Stale References',
  '',
  '| Theorem ID | Stale references | Source/topology counterparts |',
  '|---|---|---|'
);
for (const row of sourceCounterparts.slice(0, 200)) {
  const references = row.references.map((reference) => `\`${reference}\``).join('<br>');
  const counterparts = row.counterparts.map((counterpart) => `\`${counterpart}\``).join('<br>');
  lines.push(`| \`${row.theoremId}\` | ${references} | ${counterparts} |`);
}
if (sourceCounterparts.length > 200) {
  lines.push(`| ... | ... | ${sourceCounterparts.length - 200} more rows omitted from this preview |`);
}

lines.push('', '## Ledger-Only Rows By Prefix', '', '| Prefix | Rows |', '|---|---:|');
const prefixCounts = new Map();
for (const row of ledgerOnly) {
  const prefix = row.theoremId.split('-').slice(0, 3).join('-');
  prefixCounts.set(prefix, (prefixCounts.get(prefix) ?? 0) + 1);
}
for (const [prefix, count] of [...prefixCounts.entries()].sort((left, right) => right[1] - left[1])) {
  lines.push(`| \`${tableCell(prefix)}\` | ${count} |`);
}

writeFileSync(reportPath, `${lines.join('\n')}\n`, 'utf8');
console.log(`Wrote ${path.relative(repoRoot, reportPath)}`);
console.log(`Ledger fallback rows: ${fallbackIds.size}`);
console.log(`Resolvable references: ${resolvable.length}`);
console.log(`Stale references: ${staleReferences.length}`);
